1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	function calculateComponentPremium(items: any[]): number {
16	  const counts: Record<string, number> = {};
17	  for (const item of items) {
18	    if (COMPONENT_TYPES.has(item.type)) {
19	      counts[item.type] = (counts[item.type] ?? 0) + 1;
20	    }
21	  }
22	  let premium = 0;
23	  for (const count of Object.values(counts)) {
24	    if (count === BLOCK_SIZE) {
25	      premium += BLOCK_PREMIUM;
26	    } else {
27	      premium += count * COMPONENT_PREMIUM;
28	    }
29	  }
30	  return premium;
31	}
32	
33	function calculateItemPremium(item: any): number {
34	  if (COMPONENT_TYPES.has(item.type)) {
35	    return 0;
36	  }
37	  const base = BASE_PREMIUMS[item.type] ?? 0;
38	  let premium = base;
39	  if (item.cursed) {
40	    premium += base * 0.5;
41	  }
42	  if (item.enchantment >= 5) {
43	    premium += base * 0.3;
44	  }
45	  return premium;
46	}
47	
48	function calculateQuotePremium(items: any[]): number {
49	  const itemTotal = items.reduce((sum, item) => sum + calculateItemPremium(item), 0);
50	  const componentTotal = calculateComponentPremium(items);
51	  const nonComponentBase = items
52	    .filter((item: any) => !COMPONENT_TYPES.has(item.type))
53	    .reduce((sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
54	  const policyBase = nonComponentBase + componentTotal;
55	  const firstInsurance = policyBase * 0.1;
56	  return Math.ceil(PROCESSING_FEE + itemTotal + componentTotal + firstInsurance);
57	}
58	
59	export function processScenario(scenario: any): any {
60	  const results = scenario.steps.map((step: any) => {
61	    if (step.op === "quote") {
62	      return { premium: calculateQuotePremium(step.items) };
63	    }
64	  });
65	  return { results };
66	}
